	filePath,
	oldString,
	newString,
}: {
	filePath: string;
	oldString: string;
	newString: string;
}) => {
	const diff = `--- a/${filePath}
+++ b/${filePath}
@@ -1,${oldString.split('\n').length} +1,${newString.split('\n').length} @@
${oldString
	.split('\n')
	.map((line) => '-' + line)
	.join('\n')}
${newString
	.split('\n')
	.map((line) => '+' + line)
	.join('\n')}`;

	return (
		<>
			<ContentSection label="File Path">
				<code
					style={{
						background: '#f9f9f9',
