import CareerCta from "./CareerCta";
import ContactFormSection from "./ContactFormSection";
import ContactImg from "./ContactImg";

export default function Contact() {
  return (
    <main className="bg-gray-900">
      <article className="relative bg-gray-900">
        <ContactImg />
        <ContactFormSection />
      </article>
      <CareerCta />
    </main>
  );
}

import React from "react";
import { Disclosure } from "@headlessui/react";
import faq from "../../data/faq";

function classNames(...classes) {
  return classes.filter(Boolean).join(" ");
}

export default function FaqList() {
  return (
    <dl className="mt-6 space-y-6 ">
      {faq.map((faq) => (
        <Disclosure as="div" key={faq.question} className="pt-6">
          {({ open }) => (
            <React.Fragment>
              <dt className="text-lg">
                <Disclosure.Button className="text-left w-full flex justify-between items-start text-gray-400">
                  <span className="font-medium text-white">{faq.question}</span>
                  <span className="ml-6 h-7 flex items-center">
                    <svg
                      className={classNames(
                        open ? "-rotate-180" : "rotate-0",
                        "h-6 w-6 transform"
                      )}
                      xmlns="http://www.w3.org/2000/svg"
                      viewBox="0 0 24 24"
                      fill="currentColor">
                      <path
                        fillRule="evenodd"
                        d="M12.53 16.28a.75.75 0 0 1-1.06 0l-7.5-7.5a.75.75 0 0 1 1.06-1.06L12 14.69l6.97-6.97a.75.75 0 1 1 1.06 1.06l-7.5 7.5Z"
                        clipRule="evenodd"
                      />
                    </svg>
                  </span>
                </Disclosure.Button>
              </dt>
              <Disclosure.Panel as="dd" className="mt-2 pr-12">
                <p className="text-base text-gray-500">{faq.answer}</p>
              </Disclosure.Panel>
            </React.Fragment>
          )}
        </Disclosure>
      ))}
    </dl>
  );
}

import ContactForm from "./ContactForm";

export default function ContactFormSection() {
  return (
    <section className="relative gap-5 py-16 px-4 sm:py-24 sm:px-6 lg:px-8 lg:max-w-7xl lg:mx-auto lg:py-32 lg:grid lg:grid-cols-2 ">
      <section className="max-w-md mx-auto sm:max-w-lg lg:mx-0">
        <h2 className="text-3xl font-extrabold tracking-tight sm:text-4xl text-white">
          Let's work together
        </h2>
        <p className="mt-4 text-lg text-gray-500 sm:mt-3">
          We’d love to hear from you! Send us a message using the contact form
          or email us. We’d love to hear from you!
        </p>
        <ContactForm />
      </section>
    </section>
  );
}

export default function ContactImg() {
  return (
    <section className="lg:absolute lg:inset-y-0 lg:right-0 lg:w-1/2">
      <img
        className="h-56 w-full object-cover lg:absolute lg:h-full object-center"
        src="https://images.unsplash.com/photo-1497215641119-bbe6d71ebaae?ixlib=rb-1.2.1&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=774&q=80"
        alt=""
      />
    </section>
  )
}

import { Link } from "react-router-dom";

export default function CareerCta() {
  const ResetLocation = () => window.scrollTo(0, 0);
  return (
    <article className="bg-grape-400">
      <section className="max-w-md mx-auto text-center py-16 px-4 sm:max-w-2xl sm:py-24 sm:px-6 lg:px-8 lg:py-32">
        <h2 className="text-3xl font-extrabold sm:text-4xl">
          <span className="block text-white">Looking for a new career?</span>
          <span className="block text-[color:var(--primary-font-color)]">We’re hiring.</span>
        </h2>
        <Link
          onClick={ResetLocation}
          to="/jobs"
          className="mt-8 w-full inline-flex items-center justify-center py-3 px-5 bg-white border border-transparent rounded-md shadow-md text-base font-medium text-grape-600 hover:bg-grape-50 sm:w-auto"
        >
          See open positions
        </Link>
      </section>
    </article>
  )
}

