	const diff = `--- a/${filePath}
+++ b/${filePath}
@@ -1,${oldString.split('\n').length} +1,${newString.split('\n').length} @@
${oldString
	.split('\n')
	.map((line) => '-' + line)
	.join('\n')}
${newString
	.split('\n')
	.map((line) => '+' + line)
	.join('\n')}`;

